translation.x:
my rohr= FindPart('kabelkanalprofil', 'traverse','eckverbinder','kitos_aufbaurohr');
my b= rohr ?  Parent('mainstructure', rohr) :0;
my t= b ? ChildOfTypeDeep(b, 'traverse') : 0;
my sym= t ? Feature(t, 'Symetrie') : '';
my turn= t ? Feature(t, 'Turn') : '' ;
((sym EQ 'L' AND turn EQ 'V') OR (sym EQ 'R' AND turn EQ 'H')) ? -7.5 : ((sym EQ 'R' AND turn EQ 'V') OR (sym EQ 'L' AND turn EQ 'H')) ? 7.5 : 0;

my rohr= FindPart('kabelkanalprofil', 'traverse','eckverbinder','kitos_aufbaurohr');
my b= rohr ?  Parent('mainstructure', rohr) :0;
my t= b ? ChildOfTypeDeep(b, 'traverse') : 0;
my sym= t ? Feature(t, 'Symetrie') : '';
my turn= t ? Feature(t, 'Turn') : '' ;
((sym EQ 'L' AND turn EQ 'V') OR (sym EQ 'R' AND turn EQ 'H')) ? -7.5 : ((sym EQ 'R' AND turn EQ 'V') OR (sym EQ 'L' AND turn EQ 'H')) ? 7.5 : 0;

my t= FindPart('traverse');
my t= not t ? FindPart('kabelkanalprofil','traverse') : t;
my parent= t ?  Parent('mainstructure', t) : 0;
my isbasis= parent AND IsSubTypeOf(parent, 'basistraeger') ? true : false;
my sym= t ? Feature(t, 'Symetrie') : '';
my turn= t ? Feature(t, 'Turn') : '' ;
((isbasis AND sym EQ 'L' AND turn EQ 'V') OR (isbasis AND sym EQ 'R' AND turn EQ 'H')) ? -7.5 : ((isbasis AND sym EQ 'R' AND turn EQ 'V') OR (isbasis AND sym EQ 'L' AND turn EQ 'H')) ? 7.5 : 0;

